{
  "project_id": "proj-2026-checkout",
  "decision_rights": [
    {
      "decision_type": "new requirement",
      "authority": "BA Lead",
      "escalation": "PM",
      "artefact": "Jira REQ"
    },
    {
      "decision_type": "scope change",
      "authority": "Steering Chair",
      "escalation": "Sponsor",
      "artefact": "Jira CR"
    },
    {
      "decision_type": "priority change",
      "authority": "Product Owner",
      "escalation": "PM",
      "artefact": "Backlog"
    },
    {
      "decision_type": "baseline update",
      "authority": "BA Lead + PO",
      "escalation": "PM",
      "artefact": "Confluence page"
    }
  ],
  "change_control": {
    "steps": [
      "submit_cr",
      "impact_assess",
      "authority_review",
      "decide",
      "baseline_update"
    ],
    "decision_sla_days": 5
  },
  "comms_plan": [
    {
      "audience": "Sponsor",
      "info": "status + risks",
      "format": "summary",
      "frequency": "weekly",
      "channel": "email",
      "feedback": "standing review slot"
    },
    {
      "audience": "Dev team",
      "info": "detailed reqs",
      "format": "full doc",
      "frequency": "per sprint",
      "channel": "Jira",
      "feedback": "refinement questions log"
    },
    {
      "audience": "Ops",
      "info": "release plan",
      "format": "checklist",
      "frequency": "pre-release",
      "channel": "Slack",
      "feedback": "ack + blockers thread"
    }
  ],
  "owner": "jane@team.io",
  "last_reviewed": "2026-05-23"
}
